export class AttemptAccess extends Contract {
    static exec(attempt, entryFeePayment) {
        const [teacher] = attempt._owners;
        const [student] = entryFeePayment._owners;
        if (attempt.answerCommitment !== '') throw new Error('Already committed');
        if (attempt.status !== 'available') throw new Error('Not available');
        if (entryFeePayment._satoshis < attempt.entryFee) throw new Error('Insufficient fee');
        if (entryFeePayment.recipient !== teacher) throw new Error('Wrong recipient');
        attempt.transfer(student);
        entryFeePayment.transfer(teacher);
        return [entryFeePayment, attempt];
    }
}
